impl Args {
    fn log_level(&self) -> &'static str {
        if self.silent {
            "error"
        } else if self.debug {
            "trace"
        } else if self.verbose {
            "debug"
        } else {
            "info"
        }
    }
}

fn init_tracing(args: &Args) {
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new(args.log_level()));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_writer(std::io::stderr)
        .init();
}

fn open_input(path: Option<&PathBuf>) -> Result<Box<dyn BufRead>> {
    match path {
        Some(p) => {
            let f = File::open(p)
                .with_context(|| format!("opening input file {}", p.display()))?;
            Ok(Box::new(BufReader::new(f)))
        }
        None => Ok(Box::new(BufReader::new(io::stdin()))),
    }
}

/// Hybrid stream reader: parses back-to-back JSON values without
/// requiring delimiters (for partisan / extendo compat — see #60),
/// AND re-syncs after parse errors so the stream can continue past
/// a single malformed envelope (for human-driven pipelines — see
/// #61).
///
/// On parse error the reader:
/// 1. Drains the bytes the parser consumed before failing
///    (`Deserializer::byte_offset`). For most type-mismatch errors
///    on well-formed JSON (the partisan-compat shape) this is the
///    whole envelope, so the next call starts cleanly at the next
///    envelope.
/// 2. Skips past a newline if one is *already* buffered — recovers
///    cleanly for newline-delimited input from a human pipeline.
/// 3. **Never blocks reading more input from upstream on the
///    recovery path.** Doing so was the bug that made partisan
///    deadlock pre-fix: partisan-style envelopes have no trailing
///    newline, so a blocking re-sync on parse error wedged the
///    process before the caller's `{"error": ...}` line could be
///    written, and partisan's `stdout.readline()` waited forever
///    for output that would never come. See #37 / #57's
///    AvuValue-array trace.
/// 4. Surfaces the error to the caller (which emits an in-band
///    `{"error": ...}` line) and returns.
///
/// Forward-progress guarantee: if the parser consumed zero bytes
/// AND no newline is buffered, the reader discards everything in
/// the buffer rather than looping on the same error.
struct StreamingEnvelopeReader<R: BufRead> {
    reader: R,
    buf: Vec<u8>,
}

impl<R: BufRead> StreamingEnvelopeReader<R> {
    fn new(reader: R) -> Self {
        Self {
            reader,
            buf: Vec::new(),
        }
    }

    /// Try to read the next JSON envelope. Returns `Ok(None)` on
    /// EOF, `Ok(Some(Ok(value)))` on a clean parse, or
    /// `Ok(Some(Err(parse_err)))` on parse failure (after
    /// re-syncing past the next `\n`). Only an underlying-IO error
    /// surfaces as `Err`.
    fn next_envelope<T: DeserializeOwned>(
        &mut self,
    ) -> io::Result<Option<Result<T, serde_json::Error>>> {
        loop {
            // Make sure we have at least some bytes to attempt parsing.
            // `read_more` blocks (BufRead::fill_buf semantics) until at
            // least one byte arrives — exactly the right behaviour for
            // an interactive subprocess where partisan is sleeping
            // between envelopes.
            if self.buf.is_empty() && self.read_more()? == 0 {
                return Ok(None);
            }

            // Try to parse one value from `buf`. Using
            // `Deserializer::from_slice(...).into_iter()` lets us
            // discover both the parsed value and the consumed
            // byte-range (`byte_offset`) without committing to
            // anything beyond — drop the iterator before mutating
            // `buf`.
            let (parse_result, consumed) = {
                let mut iter = Deserializer::from_slice(&self.buf).into_iter::<T>();
                let result = iter.next();
                let offset = iter.byte_offset();
                (result, offset)
            };

            match parse_result {
                Some(Ok(value)) => {
                    self.buf.drain(..consumed);
                    return Ok(Some(Ok(value)));
                }
                None => {
                    // The slice held only whitespace (or was empty).
                    // Drain whatever was scanned and read more.
                    self.buf.drain(..consumed);
                    if self.buf.is_empty() && self.read_more()? == 0 {
                        return Ok(None);
                    }
                }
                Some(Err(e)) if e.is_eof() => {
                    // Partial value; need more input to complete it.
                    if self.read_more()? == 0 {
                        // EOF mid-value. Surface the error so the
                        // caller emits an in-band annotation; the
                        // stream then ends naturally on the next
                        // call.
                        return Ok(Some(Err(e)));
                    }
                }
                Some(Err(e)) => {
                    // Real parse / visitor-level error. Drain what
                    // the parser consumed and then either skip past
                    // a buffered newline (recoverable: human-driven
                    // pipeline with multiple envelopes per line) or
                    // drop the remaining buffer entirely
                    // (non-recoverable from this single envelope).
                    // Critically, **never read more from upstream
                    // on the recovery path** — partisan-style
                    // callers send one envelope per request and are
                    // already blocked waiting for the synthetic
                    // error line emitted by the caller below, so
                    // any blocking read here would deadlock. See
                    // #37.
                    self.buf.drain(..consumed);
                    if let Some(nl) = self.buf.iter().position(|&b| b == b'\n') {
                        self.buf.drain(..=nl);
                    } else {
                        self.buf.clear();
                    }
                    return Ok(Some(Err(e)));
                }
            }
        }
    }

    fn read_more(&mut self) -> io::Result<usize> {
        let chunk = self.reader.fill_buf()?;
        if chunk.is_empty() {
            return Ok(0);
        }
        let n = chunk.len();
        self.buf.extend_from_slice(chunk);
        self.reader.consume(n);
        Ok(n)
    }

    // `advance_past_newline` previously sat here as the recovery
    // path on parse error. It blocked on `read_until(b'\n', ...)`
    // when the buffer had no newline — a deadlock against
    // partisan-style callers that never send a newline and are
    // themselves blocked reading the synthetic error line we'd
    // write next. Removed in #37; the inline recovery in
    // `next_envelope` does the same job non-blockingly.
}

/// Extract a trailing X.Y.Z version from an iRODS `relVersion`
/// string (e.g. `"rods4.3.5"` → `"4.3.5"`). Mirrors upstream
/// baton's `([0-9]+\.[0-9]+\.[0-9]+)$` regex
/// (`baton/src/baton.c:212`) but hand-rolled to avoid pulling in
/// the `regex` crate for one call site.
///
/// Returns `None` when no trailing X.Y.Z is present — caller
/// surfaces this as the same error upstream baton emits ("Failed to
/// match server version").
fn extract_server_version(rel_version: &str) -> Option<String> {
    // Walk from the end taking digits and dots. The result is the
    // longest trailing run of `[0-9.]`, which we then validate is
    // exactly three non-empty all-digit components.
    let trail_chars = rel_version
        .chars()
        .rev()
        .take_while(|c| c.is_ascii_digit() || *c == '.')
        .count();
    if trail_chars == 0 || trail_chars > rel_version.len() {
        return None;
    }
    // ASCII digits + '.' are single-byte, so char count == byte count.
    let trail = &rel_version[rel_version.len() - trail_chars..];
    let parts: Vec<&str> = trail.split('.').collect();
    if parts.len() == 3
        && parts
            .iter()
            .all(|p| !p.is_empty() && p.bytes().all(|b| b.is_ascii_digit()))
    {
        Some(trail.to_string())
    } else {
        None
    }
}

fn run_server_version() -> Result<()> {
    let mut conn = RodsConnection::connect_from_env().context("connecting to iRODS")?;
    conn.login_from_auth_file().context("authenticating")?;
    let rel = conn
        .server_version_relversion()
        .context("rcGetMiscSvrInfo")?;
    let version = extract_server_version(&rel).ok_or_else(|| {
        anyhow::anyhow!("failed to match server version in {:?}", rel)
    })?;
    println!("{}", version);
    Ok(())
}

fn main() -> Result<()> {
    let args = Args::parse();

    // --version short-circuits before tracing init / iRODS connect:
    // doesn't need either, and we don't want spurious log lines on
    // stderr ahead of partisan's `subprocess.run(..., capture_output=True)`
    // parsing of stdout.
    if args.version {
        println!("{}", baton_rs::report_version());
        return Ok(());
    }

    init_tracing(&args);

    if args.zone.is_some() {
        tracing::warn!(
            "--zone is accepted for compatibility but currently ignored; \
             use the per-record metaquery 'zone' field instead"
        );
    }
    if args.single_server {
        tracing::debug!("--single-server is a no-op in baton-rs");
    }

    // --server-version short-circuits before the NDJSON loop —
    // matches upstream baton-do.c:162-181 ordering.
    if args.server_version {
        return run_server_version();
    }

    let mut conn = RodsConnection::connect_from_env().context("connecting to iRODS")?;
    conn.login_from_auth_file().context("authenticating")?;
    let mut session =
        ReconnectingSession::new(conn, Duration::from_secs(args.connect_time));

    let stdout = io::stdout();
    let mut out = stdout.lock();

    let reader = open_input(args.file.as_ref())?;
    let mut had_errors = false;

    // Hybrid stream reader: handles back-to-back JSON without
    // delimiters (partisan / extendo compat per #60) AND re-syncs
    // at `\n` after parse errors so a malformed envelope doesn't
    // kill the rest of the stream (per #61). Whitespace between
    // values is implicitly skipped, so existing newline-delimited
    // test fixtures still parse cleanly.
    let mut stream = StreamingEnvelopeReader::new(reader);
    while let Some(parse_result) = stream
        .next_envelope::<BatonDoEnvelope>()
        .context("reading input")?
    {
        // Reconnect at record boundaries when the wall-clock watchdog
        // says it's time. Reconnect failures are fail-fast — there's
        // no useful in-band annotation when the connection itself is
        // broken.
        let conn = session.maybe_reconnect().context("reconnecting to iRODS")?;

        match parse_result {
            Ok(envelope) => {
                let output = dispatch_one(conn, envelope);
                if output.error.is_some() {
                    had_errors = true;
                }
                serde_json::to_writer(&mut out, &output)
                    .context("writing output line")?;
                writeln!(&mut out).context("writing newline")?;
            }
            Err(err) => {
                // Parse-failure path: no envelope means we can't build
                // a full BatonDoOutput. Emit a stand-alone error
                // object and keep going. The hybrid reader has
                // already advanced past the next `\n` (if any), so
                // the next iteration resumes at a clean line
                // boundary. Tracked as a documented divergence from
                // upstream's parse-error wire shape in issue #37.
                had_errors = true;
                let baton_err = BatonError {
                    code: -1,
                    message: format!("invalid envelope: {}", err),
                };
                serde_json::to_writer(
                    &mut out,
                    &serde_json::json!({ "error": baton_err }),
                )
                .context("writing parse-error line")?;
                writeln!(&mut out).context("writing newline")?;
            }
        }

        if args.unbuffered {
            out.flush().context("flushing output")?;
        }
    }

    if had_errors && !args.no_error {
        std::process::exit(1);
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::extract_server_version;

    #[test]
    fn extract_server_version_strips_rods_prefix() {
        // Real shape on iRODS 4.x: relVersion = "rods<X>.<Y>.<Z>".
        assert_eq!(
            extract_server_version("rods4.3.5").as_deref(),
            Some("4.3.5")
        );
        assert_eq!(
            extract_server_version("rods4.2.7").as_deref(),
            Some("4.2.7")
        );
    }

    #[test]
    fn extract_server_version_accepts_bare_version() {
        // Defensive: if a future iRODS version drops the prefix, the
        // bare X.Y.Z form should still parse.
        assert_eq!(
            extract_server_version("4.3.5").as_deref(),
            Some("4.3.5")
        );
    }

    #[test]
    fn extract_server_version_handles_multi_digit_components() {
        assert_eq!(
            extract_server_version("rods10.20.30").as_deref(),
            Some("10.20.30")
        );
    }

    #[test]
    fn extract_server_version_rejects_non_xyz_shape() {
        // Two-component "X.Y" is not a valid iRODS relVersion shape;
        // upstream's regex requires exactly three.
        assert!(extract_server_version("rods4.3").is_none());
        // Four-component would also slip past a less-strict parser.
        assert!(extract_server_version("rods4.3.5.0").is_none());
        // Empty / non-version inputs.
        assert!(extract_server_version("").is_none());
        assert!(extract_server_version("rods").is_none());
    }

    #[test]
    fn extract_server_version_rejects_trailing_non_digit_dot() {
        // The trailing run must be all digits + dots. A trailing
        // letter (e.g. "rods4.3.5-rev2") leaves no clean X.Y.Z at
        // end-of-string, so the parser should return None — partisan's
        // upstream split("-",1)[0] handles dash-suffixed shapes by
        // taking the prefix, but a trailing letter without a dash
        // separator is malformed and we mirror upstream's regex
        // strictness.
        assert!(extract_server_version("rods4.3.5x").is_none());
    }
}
